import{_ as a,c as p,d as e,a as l,e as t,b as s,w as d,r,o as u}from"./app-CK2jbmJc.js";const g={},h={href:"https://baike.baidu.com/item/%E8%89%BE%E4%BC%A6%C2%B7%E9%BA%A6%E5%B8%AD%E6%A3%AE%C2%B7%E5%9B%BE%E7%81%B5/3940576",target:"_blank",rel:"noopener noreferrer"};function m(k,n){const i=r("RouteLink"),o=r("ExternalLinkIcon");return u(),p("div",null,[n[8]||(n[8]=e('<blockquote><p>计算机专业导论笔记，计算机学科处处体现小技巧，但我要学的是一种大思维，如何去设计、构造和应用，而不仅仅是一种编程和算法。</p></blockquote><h2 id="从小白鼠试毒引出计算思维" tabindex="-1"><a class="header-anchor" href="#从小白鼠试毒引出计算思维"><span>从小白鼠试毒引出计算思维</span></a></h2><h3 id="问题" tabindex="-1"><a class="header-anchor" href="#问题"><span>问题</span></a></h3><p>小白鼠实毒：有1000瓶水，小白鼠只要尝一点带毒的水24小时内就会死亡，至少需要多少只小白鼠才能在24小时内鉴别出哪瓶水有毒？</p><div class="bannertop"> 一些启发：这里觉得难是因为充斥了太多的变量：死或不死、喝或不喝、有毒无毒，变量多的问题就像一团乱麻，生活里一些难题也是这样，甚至更难。因为现实中一些事和人不是0和1，不是非黑即白的，也因此我更喜欢计算机的世界。简单直接，代码写错了，就是run不动，泾渭分明。 </div><h3 id="背后的思维模式" tabindex="-1"><a class="header-anchor" href="#背后的思维模式"><span>背后的思维模式</span></a></h3><ul><li>1000瓶水编号：0-999（这是十进制，无法继续）使用<strong>转换思维</strong> ：转换成二进制</li><li>确立十位二进制的方式表达：运用了<strong>递推思维</strong></li><li>多种含义用01串表达，这是<strong>0和1的思维</strong></li><li>同样一串数字可以表达不同的含义，这是理解计算机思维的关键</li></ul>',7)),l("p",null,[n[1]||(n[1]=t("计算思维是",-1)),n[2]||(n[2]=l("strong",null,"运用科学计算的基础概念去求解问题、设计系统和理解人类行为。",-1)),n[3]||(n[3]=t("（周以真）本博客在2025年也提到过",-1)),s(i,{to:"/blogs/life/thingy.html#computational-thinking"},{default:d(()=>[...n[0]||(n[0]=[t("《computational thinking》",-1)])]),_:1})]),n[9]||(n[9]=l("ul",null,[l("li",null,[t("此外，这道题如果用"),l("strong",null,"二分法"),t("求解，时间不够，因为这是串行使用，如果是"),l("strong",null,"并行使用二分"),t("法，完全可以。（串行并行也是一种计算机思维））")]),l("li",null,"这里也涉及到符号变换、逻辑推理思维。")],-1)),n[10]||(n[10]=l("h2",{id:"计算机的理论模型-图灵机",tabindex:"-1"},[l("a",{class:"header-anchor",href:"#计算机的理论模型-图灵机"},[l("span",null,"计算机的理论模型：图灵机")])],-1)),n[11]||(n[11]=l("h3",{id:"图灵和图灵机",tabindex:"-1"},[l("a",{class:"header-anchor",href:"#图灵和图灵机"},[l("span",null,"图灵和图灵机")])],-1)),l("p",null,[l("a",h,[n[4]||(n[4]=t("Alan Turning",-1)),s(o)]),n[5]||(n[5]=t(" 于1937年发表论文，提出",-1)),n[6]||(n[6]=l("strong",null,"图灵机模型概念",-1)),n[7]||(n[7]=t("；后来冯诺伊曼根据此概念设计出世界上第一台电子计算机；",-1))]),n[12]||(n[12]=e('<p>1950年，Turning 发表了划时代文章《机器能思考吗》，成为人工智能的开山之作；</p><p>1966年，计算机界设计最高荣誉奖：图灵奖。</p><h3 id="图灵机基本操作-计算概念" tabindex="-1"><a class="header-anchor" href="#图灵机基本操作-计算概念"><span>图灵机基本操作 &amp; 计算概念</span></a></h3><p><strong>什么是计算？图灵的观点</strong></p><p>计算是计算者（人或机器）对一条两端可无限延长的纸带上的一串0或1，执行指令，一步一步地改变纸带上的0或1，经过有限步骤最后得到一个满足预先规定的符号串的<strong>变换过程</strong>。</p><p>以上，也是关于<strong>数据、指令、程序及程序/指令自动执行</strong>的基本思想。</p><p>基本操作如下： <img src="https://cetacea-1304984885.cos.ap-shanghai.myqcloud.com/pieces/2026-04-15 22.29.52.png" alt=""></p>',7))])}const f=a(g,[["render",m]]),c=JSON.parse('{"path":"/blogs/tech/2026/0512.html","title":"计算思维","lang":"en-US","frontmatter":{"title":"计算思维","date":"2026-05-12T00:00:00.000Z","categories":["tech"],"tags":["science"]},"headers":[{"level":2,"title":"从小白鼠试毒引出计算思维","slug":"从小白鼠试毒引出计算思维","link":"#从小白鼠试毒引出计算思维","children":[{"level":3,"title":"问题","slug":"问题","link":"#问题","children":[]},{"level":3,"title":"背后的思维模式","slug":"背后的思维模式","link":"#背后的思维模式","children":[]}]},{"level":2,"title":"计算机的理论模型：图灵机","slug":"计算机的理论模型-图灵机","link":"#计算机的理论模型-图灵机","children":[{"level":3,"title":"图灵和图灵机","slug":"图灵和图灵机","link":"#图灵和图灵机","children":[]},{"level":3,"title":"图灵机基本操作 & 计算概念","slug":"图灵机基本操作-计算概念","link":"#图灵机基本操作-计算概念","children":[]}]}],"git":{"createdTime":null,"updatedTime":null,"contributors":[]},"filePathRelative":"blogs/tech/2026/0512.md"}');export{f as comp,c as data};
